INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('8eeee58e-6954-549e-ba2f-d429e5aea3fd', '4c6c0fcc-cb90-4b1a-88cc-010c3254fef6', 'I have ___ red pen.', '我有一支紅色的筆。', 'a', 'the', 'some', 'any', 'a 為不定冠詞，用於單數可數名詞前，表示「一個」。', 'a 像一個小勾，代表「一個」。'),
('8a6751fd-4fa1-5fa0-8f99-e8c1f2149195', '2148b226-a44f-453e-ac23-6e310525b3c4', 'The museum is both beautiful ___ informative.', '這間博物館既美麗又充滿知識。', 'and', 'but', 'or', 'so', '連接詞，與 both 搭配形成 both...and... 結構。', 'both...and... (兩者皆是)'),
('adce1d0e-4b69-5bf0-9550-f80243c82b2d', 'c65a0c33-e9b1-448a-98db-bb934683f81c', 'He is very smart, ___ he is sometimes lazy.', '他很聰明，但是他有時很懶惰。', 'but', 'and', 'so', 'or', '表示轉折 (但是)', '看到 but 就要想到轉折 (轉折 → but)');
